import requests

def test_billpay_unregistered_biller():
    base_url = 'http://localhost:8080'
    headers = {'Authorization': 'Bearer CUST_TOKEN_001'}
    payload = {
        'amount': 500,
        'biller_id': 'BILLER_UNKNOWN',
        'customer_id': 'CUST_001'
    }
    resp = requests.post(f'{base_url}/billpay', json=payload, headers=headers)
    assert resp.status_code in [400, 404]
    data = resp.json()
    assert 'biller' in data.get('message', '').lower() or 'not found' in data.get('message', '').lower()
